30: import java.util.Optional;
31: import java.util.PriorityQueue;
32: import java.util.Set;
33: 
34: /**
35:  * This is a helper class to facilitate tracking transaction state while cleaning the log. It maintains a set
36:  * of the ongoing aborted and committed transactions as the cleaner is working its way through the log. This
37:  * class is responsible for deciding when transaction markers can be removed and is therefore also responsible
38:  * for updating the cleaned transaction index accordingly.
39:  */
40: public class CleanedTransactionMetadata {
41:     private final Set<Long> ongoingCommittedTxns = new HashSet<>();
42:     private final Map<Long, AbortedTransactionMetadata> ongoingAbortedTxns = new HashMap<>();
43: 
44:     /**
45:      * Minheap of aborted transactions sorted by the transaction first offset
46:      */
47:     private final PriorityQueue<AbortedTxn> abortedTransactions = new PriorityQueue<>(
48:             Comparator.comparingLong(AbortedTxn::firstOffset)
49:     );
50: 
51:     /**
52:      * Output cleaned index to write retained aborted transactions
53:      */
54:     private Optional<TransactionIndex> cleanedIndex = Optional.empty();
55: 
56:     /**
57:      * Update the cleaned index.
58:      *
59:      * @param cleanedIndex The new cleaned index
60:      */
61:     public void setCleanedIndex(Optional<TransactionIndex> cleanedIndex) {
62:         this.cleanedIndex = cleanedIndex;
63:     }
64: 
65:     /**
66:      * Update the cleaned transaction state with the new found aborted transactions that has just been traversed.
67:      *
68:      * @param abortedTransactions The new found aborted transactions to add
69:      */
70:     public void addAbortedTransactions(List<AbortedTxn> abortedTransactions) {
71:         this.abortedTransactions.addAll(abortedTransactions);
72:     }
73: 
74:     /**
75:      * Update the cleaned transaction state with a control batch that has just been traversed by the cleaner.
76:      * Return true if the control batch can be discarded.
77:      *
78:      * @param controlBatch The control batch that been traversed
79:      *
80:      * @return True if the control batch can be discarded
81:      */
82:     public boolean onControlBatchRead(RecordBatch controlBatch) {
83:         consumeAbortedTxnsUpTo(controlBatch.lastOffset());
84: 
85:         Iterator<Record> controlRecordIterator = controlBatch.iterator();
86:         if (controlRecordIterator.hasNext()) {
87:             Record controlRecord = controlRecordIterator.next();
88:             ControlRecordType controlType = ControlRecordType.parse(controlRecord.key());
89:             long producerId = controlBatch.producerId();
90: 
91:             switch (controlType) {
92:                 case ABORT:
93:                     AbortedTransactionMetadata abortedTxnMetadata = ongoingAbortedTxns.remove(producerId);
94: 
95:                     // Retain the marker until all batches from the transaction have been removed.
96:                     if (abortedTxnMetadata != null && abortedTxnMetadata.lastObservedBatchOffset.isPresent()) {
97:                         cleanedIndex.ifPresent(index -> {
98:                             try {
99:                                 index.append(abortedTxnMetadata.abortedTxn);
100:                             } catch (IOException e) {
101:                                 throw new RuntimeException(e);
102:                             }
103:                         });
104:                         return false;
105:                     }
106: 
107:                     return true;
108: 
109:                 case COMMIT:
110:                     // This marker is eligible for deletion if we didn't traverse any batches from the transaction
111:                     return !ongoingCommittedTxns.remove(producerId);
112: 
113:                 default:
114:                     return false;
115:             }
116:         } else {
117:             // An empty control batch was already cleaned, so it's safe to discard
118:             return true;
119:         }
120:     }
121: 
122:     private void consumeAbortedTxnsUpTo(long offset) {
123:         while (!abortedTransactions.isEmpty() && abortedTransactions.peek().firstOffset() <= offset) {
124:             AbortedTxn abortedTxn = abortedTransactions.poll();
125:             if (abortedTxn != null) {
126:                 ongoingAbortedTxns.computeIfAbsent(abortedTxn.producerId(), id -> new AbortedTransactionMetadata(abortedTxn));
127:             }
128:         }
129:     }
130: 
131:     /**
132:      * Update the transactional state for the incoming non-control batch. If the batch is part of
133:      * an aborted transaction, return true to indicate that it is safe to discard.
134:      *
135:      * @param batch The batch to read when updating the transactional state
136:      *
137:      * @return Whether the batch is part of an aborted transaction or not
138:      */
139:     public boolean onBatchRead(RecordBatch batch) {
140:         consumeAbortedTxnsUpTo(batch.lastOffset());
141:         if (batch.isTransactional()) {
142:             Optional<AbortedTransactionMetadata> metadata = Optional.ofNullable(ongoingAbortedTxns.get(batch.producerId()));
143: 
144:             if (metadata.isPresent()) {
145:                 metadata.get().lastObservedBatchOffset = Optional.of(batch.lastOffset());
146:                 return true;
147:             } else {
148:                 ongoingCommittedTxns.add(batch.producerId());
149:                 return false;
150:             }
151:         } else {
152:             return false;
153:         }
154:     }
155: 
156:     private static class AbortedTransactionMetadata {
157:         Optional<Long> lastObservedBatchOffset = Optional.empty();
158:         final AbortedTxn abortedTxn;
159: 
160:         public AbortedTransactionMetadata(AbortedTxn abortedTxn) {
161:             this.abortedTxn = abortedTxn;
162:         }
163:     }
164: }
