28: /**
29:  * A hash table used for de-duplicating the log. This hash table uses a cryptographically secure hash of the key as a proxy for the key
30:  * for comparisons and to save space on object overhead. Collisions are resolved by probing. This hash table does not support deletes.
31:  */
32: public class SkimpyOffsetMap implements OffsetMap {
33: 
34:     /**
35:      * The number of bytes of space each entry uses (the number of bytes in the hash plus an 8 byte offset)
36:      */
37:     public final int bytesPerEntry;
38: 
39:     private final ByteBuffer bytes;
40: 
41:     /* the hash algorithm instance to use */
42:     private final MessageDigest digest;
43: 
44:     /* the number of bytes for this hash algorithm */
45:     private final int hashSize;
46: 
47:     /**
48:      * The maximum number of entries this map can contain
49:      */
50:     private final int slots;
51: 
52:     /* cache some hash buffers to avoid reallocating each time */
53:     private final byte[] hash1;
54:     private final byte[] hash2;
55: 
56:     /* number of entries put into the map */
